module RefModule(
    input clk,
    input reset,
    output reg [3:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 4'b0000
            q <= 4'b0000;
        end else begin
            // Binary up-counter: Increment the counter
            q <= q + 1;
        end
    end

endmodule
